#!/usr/bin/env node
/**
 * build_bundles.js — Inject scraped artwork bundles into the game's artworks.js
 * 
 * Reads JSON bundles from scripts/bundles/ and appends them to src/data/artworks.js.
 * Deduplicates by ID so re-running is safe.
 * 
 * Usage:
 *   node scripts/build_bundles.js                          # inject all bundles
 *   node scripts/build_bundles.js --bundle artworks_bundle_1.json   # specific bundle
 *   node scripts/build_bundles.js --dry-run                # preview only
 */

import fs from 'fs';
import path from 'path';
import { fileURLToPath } from 'url';

const __filename = fileURLToPath(import.meta.url);
const __dirname = path.dirname(__filename);

const ARTWORKS_FILE = path.resolve(__dirname, '../src/data/artworks.js');
const BUNDLES_DIR = path.resolve(__dirname, 'bundles');

// Parse CLI args
const args = process.argv.slice(2);
const dryRun = args.includes('--dry-run');
const bundleArg = args.find((_, i) => args[i - 1] === '--bundle');

// Read the current artworks.js
const artworksSource = fs.readFileSync(ARTWORKS_FILE, 'utf-8');

// Extract existing IDs to prevent duplicates
const existingIds = new Set();
const idRegex = /id:\s*['"]([^'"]+)['"]/g;
let match;
while ((match = idRegex.exec(artworksSource)) !== null) {
    existingIds.add(match[1]);
}
console.log(`📦 Found ${existingIds.size} existing artwork IDs in artworks.js`);

// Find the insertion point: just before the closing `];`
// We look for the LAST `];` in the file that closes the ARTWORKS array
const insertionMarker = '];\n\n// Ensure every artwork has basePrice';
const insertionIdx = artworksSource.indexOf(insertionMarker);
if (insertionIdx === -1) {
    console.error('❌ Could not find insertion point in artworks.js');
    console.error('   Looking for: ];\\n\\n// Ensure every artwork has basePrice');
    process.exit(1);
}

// Gather bundles
let bundleFiles;
if (bundleArg) {
    bundleFiles = [path.join(BUNDLES_DIR, bundleArg)];
} else {
    bundleFiles = fs.readdirSync(BUNDLES_DIR)
        .filter(f => f.endsWith('.json'))
        .map(f => path.join(BUNDLES_DIR, f));
}

if (bundleFiles.length === 0) {
    console.log('⚠️  No bundle files found in', BUNDLES_DIR);
    process.exit(0);
}

// Process each bundle
let totalAdded = 0;
let totalSkipped = 0;
let newEntries = [];

for (const bundlePath of bundleFiles) {
    const bundleName = path.basename(bundlePath);
    console.log(`\n📄 Processing: ${bundleName}`);

    let bundle;
    try {
        bundle = JSON.parse(fs.readFileSync(bundlePath, 'utf-8'));
    } catch (e) {
        console.error(`   ❌ Failed to parse: ${e.message}`);
        continue;
    }

    const artworks = bundle.artworks || [];
    console.log(`   Found ${artworks.length} artworks in bundle`);

    for (const art of artworks) {
        if (!art.id || !art.title || !art.artist) {
            continue; // Skip malformed entries
        }

        if (existingIds.has(art.id)) {
            totalSkipped++;
            continue;
        }

        existingIds.add(art.id);

        // Format the JS object entry
        const entry = [
            `    {`,
            `        id: '${art.id.replace(/'/g, "\\'")}',`,
            `        ownerId: 'market',`,
            `        title: "${art.title.replace(/"/g, '\\"')}",`,
            `        artist: "${art.artist.replace(/"/g, '\\"')}",`,
            art.yearCreated ? `        year: "${art.yearCreated}",` : null,
            `        medium: "${(art.medium || 'Oil on canvas').replace(/"/g, '\\"')}",`,
            `        askingPrice: ${art.basePrice || 100000},`,
            `        basePrice: ${art.basePrice || 100000},`,
            `        genre: "${art.genre || 'unknown'}",`,
            `        tier: "${art.tier || 'mid-career'}",`,
            `        sprite: "${art.sprite || art.id + '.jpg'}",`,
            `        _source: "scraped"`,
            `    }`,
        ].filter(Boolean).join('\n');

        newEntries.push(entry);
        totalAdded++;
    }
}

console.log(`\n${'═'.repeat(60)}`);
console.log(`  📊 SUMMARY`);
console.log(`${'═'.repeat(60)}`);
console.log(`  New artworks to add:  ${totalAdded}`);
console.log(`  Duplicates skipped:   ${totalSkipped}`);
console.log(`  Bundles processed:    ${bundleFiles.length}`);

if (totalAdded === 0) {
    console.log('\n  ✅ Nothing new to add. artworks.js is up to date.');
    process.exit(0);
}

if (dryRun) {
    console.log('\n  🔍 DRY RUN — No changes written.');
    console.log(`  Would add ${totalAdded} artworks to artworks.js`);
    console.log('\n  First 3 entries preview:');
    newEntries.slice(0, 3).forEach(e => console.log(e));
    process.exit(0);
}

// Build the injection block
const injectionBlock = `\n    // ── SCRAPED ARTWORKS (auto-generated by build_bundles.js) ─────────\n\n${newEntries.join(',\n\n')},\n`;

// Splice into artworks.js
const newSource = artworksSource.slice(0, insertionIdx) + injectionBlock + artworksSource.slice(insertionIdx);

fs.writeFileSync(ARTWORKS_FILE, newSource, 'utf-8');

console.log(`\n  ✅ Successfully injected ${totalAdded} artworks into artworks.js!`);
console.log(`  📁 File: ${ARTWORKS_FILE}`);
console.log(`${'═'.repeat(60)}\n`);
